BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Right & Left Heart Failure' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Right & Left Heart Failure', 'Right-sided and left-sided heart failure', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - Right & Left Heart Failure (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Right-Left Heart Failure - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports HF Definition?', 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports HF Definition?', '[{"id": "a", "text": "This finding is more consistent with EF Range."}, {"id": "b", "text": "Heart failure always presents without fluid overload."}, {"id": "c", "text": "Heart failure is the inability of the heart to pump sufficient blood to meet metabolic needs."}, {"id": "d", "text": "This finding excludes heart failure when EF is preserved."}]'::jsonb, '["c"]'::jsonb, 'Correct because Heart failure is the inability of the heart to pump sufficient blood to meet metabolic needs. Recognize that congestion and low forward output can coexist.', 'Right-Left Heart Failure - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During clinical handoff, which interpretation is most accurate for HFrEF?', 'During clinical handoff, which interpretation is most accurate for HFrEF?', '[{"id": "a", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "b", "text": "HFrEF is primarily a stiff non-compliant ventricle with preserved EF."}, {"id": "c", "text": "This finding is more consistent with Left HF Core."}, {"id": "d", "text": "Link reduced EF with weakened pump function."}]'::jsonb, '["d"]'::jsonb, 'Correct because HFrEF has EF <40% with a dilated, weak heart. Link reduced EF with weakened pump function.', 'Right-Left Heart Failure - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse is prioritizing care. Which statement best reflects HFpEF?', 'The nurse is prioritizing care. Which statement best reflects HFpEF?', '[{"id": "a", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "b", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "c", "text": "HFpEF has EF >50% with a stiff, non-compliant heart."}, {"id": "d", "text": "This finding is more consistent with Left HF Causes."}]'::jsonb, '["c"]'::jsonb, 'Correct because HFpEF has EF >50% with a stiff, non-compliant heart. Avoid ruling out HF just because EF is preserved.', 'Right-Left Heart Failure - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A complex symptom cluster is reviewed. Which conclusion best matches EF Range?', 'A complex symptom cluster is reviewed. Which conclusion best matches EF Range?', '[{"id": "a", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "b", "text": "Prioritize clinical symptoms over EF alone."}, {"id": "c", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "d", "text": "EF alone is always enough to diagnose or exclude HF."}]'::jsonb, '["b"]'::jsonb, 'Correct because Normal EF is 55-70%; HF diagnosis can still be made if symptoms are present regardless of EF. Prioritize clinical symptoms over EF alone.', 'Right-Left Heart Failure - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Left HF Core?', 'Which clinical judgment is most consistent with Left HF Core?', '[{"id": "a", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "b", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "c", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "d", "text": "Left-sided HF primarily causes pulmonary congestion."}]'::jsonb, '["d"]'::jsonb, 'Correct because Left-sided HF primarily causes pulmonary congestion. Map left side findings to lung congestion.', 'Right-Left Heart Failure - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Left HF Causes?', 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Left HF Causes?', '[{"id": "a", "text": "Left HF is unrelated to cardiomyopathy."}, {"id": "b", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "c", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "d", "text": "Connect structural and ischemic causes to LV failure."}]'::jsonb, '["d"]'::jsonb, 'Correct because Left HF causes include mitral/aortic valve disease, MI, chronic hypertension, cardiomyopathy. Connect structural and ischemic causes to LV failure.', 'Right-Left Heart Failure - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During clinical handoff, which interpretation is most accurate for Left HF Path?', 'During clinical handoff, which interpretation is most accurate for Left HF Path?', '[{"id": "a", "text": "Left HF pathophysiology in the note excludes alveolar fluid leakage."}, {"id": "b", "text": "LV failure first causes isolated portal venous congestion in the note."}, {"id": "c", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "d", "text": "LV failure backs blood into pulmonary veins; pressure rises and fluid leaks into alveoli causing pulmonary edema."}]'::jsonb, '["d"]'::jsonb, 'Correct because LV failure backs blood into pulmonary veins; pressure rises and fluid leaks into alveoli causing pulmonary edema. Identify sequence leading to respiratory compromise.', 'Right-Left Heart Failure - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse is prioritizing care. Which statement best reflects DOE?', 'The nurse is prioritizing care. Which statement best reflects DOE?', '[{"id": "a", "text": "Escalate evaluation when exertional dyspnea appears in risk patients."}, {"id": "b", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "c", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "d", "text": "This finding excludes heart failure when EF is preserved."}]'::jsonb, '["a"]'::jsonb, 'Correct because Dyspnea on exertion is the first symptom listed for left HF. Escalate evaluation when exertional dyspnea appears in risk patients.', 'Right-Left Heart Failure - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A complex symptom cluster is reviewed. Which conclusion best matches Orthopnea and PND?', 'A complex symptom cluster is reviewed. Which conclusion best matches Orthopnea and PND?', '[{"id": "a", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "b", "text": "Orthopnea is identified as a right-sided-only symptom in this note."}, {"id": "c", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "d", "text": "Orthopnea and PND are classic left-sided HF symptoms."}]'::jsonb, '["d"]'::jsonb, 'Correct because Orthopnea and PND are classic left-sided HF symptoms. Use nocturnal and positional dyspnea to triage severity.', 'Right-Left Heart Failure - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Pulmonary edema?', 'Which clinical judgment is most consistent with Pulmonary edema?', '[{"id": "a", "text": "Pink frothy sputum is listed as a benign right-sided finding."}, {"id": "b", "text": "Treat as high-acuity respiratory compromise."}, {"id": "c", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "d", "text": "This finding is more consistent with Right HF Causes."}]'::jsonb, '["b"]'::jsonb, 'Correct because Pink frothy sputum is a severe pulmonary edema sign in left HF. Treat as high-acuity respiratory compromise.', 'Right-Left Heart Failure - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports S3?', 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports S3?', '[{"id": "a", "text": "S3 gallop is described as a hallmark of heart failure (especially in left HF section)."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "S3 is only a normal physiologic finding in this note."}, {"id": "d", "text": "No further assessment is needed when symptoms fluctuate."}]'::jsonb, '["a"]'::jsonb, 'Correct because S3 gallop is described as a hallmark of heart failure (especially in left HF section). Interpret S3 with full volume-overload context.', 'Right-Left Heart Failure - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During clinical handoff, which interpretation is most accurate for Right HF Core?', 'During clinical handoff, which interpretation is most accurate for Right HF Core?', '[{"id": "a", "text": "Distinguish body-fluid retention pattern from pulmonary pattern."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "d", "text": "Fluid trends are not useful for cardiovascular reassessment."}]'::jsonb, '["a"]'::jsonb, 'Correct because Right-sided HF primarily causes systemic (peripheral) congestion. Distinguish body-fluid retention pattern from pulmonary pattern.', 'Right-Left Heart Failure - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse is prioritizing care. Which statement best reflects Right HF Causes?', 'The nurse is prioritizing care. Which statement best reflects Right HF Causes?', '[{"id": "a", "text": "Most common right HF cause is left-sided HF; others include tricuspid disease, pulmonary HTN, RV MI, chronic lung disease."}, {"id": "b", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "c", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "d", "text": "Aortic stenosis is listed as the dominant right-sided cause in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Most common right HF cause is left-sided HF; others include tricuspid disease, pulmonary HTN, RV MI, chronic lung disease. Search upstream causes when right-sided findings appear.', 'Right-Left Heart Failure - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A complex symptom cluster is reviewed. Which conclusion best matches Right HF Path?', 'A complex symptom cluster is reviewed. Which conclusion best matches Right HF Path?', '[{"id": "a", "text": "RV failure in this note lowers venous pressure and prevents edema."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "d", "text": "Connect venous pressure rise to peripheral signs."}]'::jsonb, '["d"]'::jsonb, 'Correct because RV failure causes venous backup and systemic fluid accumulation. Connect venous pressure rise to peripheral signs.', 'Right-Left Heart Failure - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with JVD?', 'Which clinical judgment is most consistent with JVD?', '[{"id": "a", "text": "JVD reflects elevated venous pressure and is a major right HF sign."}, {"id": "b", "text": "JVD is listed as a hallmark of isolated left alveolar pathology in this note."}, {"id": "c", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "d", "text": "This finding is more consistent with Ascites/hepatomegaly."}]'::jsonb, '["a"]'::jsonb, 'Correct because JVD reflects elevated venous pressure and is a major right HF sign. Use JVD as high-yield bedside congestion marker.', 'Right-Left Heart Failure - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Peripheral edema?', 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Peripheral edema?', '[{"id": "a", "text": "Trend bilateral edema and rapid fluid changes."}, {"id": "b", "text": "Unilateral trauma edema is listed as classic HF edema in this note."}, {"id": "c", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "d", "text": "This finding excludes heart failure when EF is preserved."}]'::jsonb, '["a"]'::jsonb, 'Correct because Right HF commonly causes bilateral peripheral pitting edema. Trend bilateral edema and rapid fluid changes.', 'Right-Left Heart Failure - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During clinical handoff, which interpretation is most accurate for Weight rule physiology?', 'During clinical handoff, which interpretation is most accurate for Weight rule physiology?', '[{"id": "a", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "b", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "c", "text": "The note states 1 kg equals 100 mL of fluid."}, {"id": "d", "text": "Rapid gain indicates fluid retention; 1 kg equals about 1 liter."}]'::jsonb, '["d"]'::jsonb, 'Correct because Rapid gain indicates fluid retention; 1 kg equals about 1 liter. Use objective weight data for early decompensation detection.', 'Right-Left Heart Failure - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse is prioritizing care. Which statement best reflects Ascites/hepatomegaly?', 'The nurse is prioritizing care. Which statement best reflects Ascites/hepatomegaly?', '[{"id": "a", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "b", "text": "This finding is more consistent with General therapy."}, {"id": "c", "text": "Recognize abdominal signs as venous-congestion progression."}, {"id": "d", "text": "This finding excludes heart failure when EF is preserved."}]'::jsonb, '["c"]'::jsonb, 'Correct because Severe right HF can cause ascites and hepatomegaly with RUQ discomfort; GI congestion can cause nausea/anorexia. Recognize abdominal signs as venous-congestion progression.', 'Right-Left Heart Failure - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A complex symptom cluster is reviewed. Which conclusion best matches Cor pulmonale?', 'A complex symptom cluster is reviewed. Which conclusion best matches Cor pulmonale?', '[{"id": "a", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "b", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "c", "text": "Chronic lung disease raises pulmonary vascular resistance and can lead to RV failure/right HF."}, {"id": "d", "text": "This finding is more consistent with Weight reporting thresholds."}]'::jsonb, '["c"]'::jsonb, 'Correct because Chronic lung disease raises pulmonary vascular resistance and can lead to RV failure/right HF. Identify cardiopulmonary linkage in chronic lung patients.', 'Right-Left Heart Failure - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Comparison matrix?', 'Which clinical judgment is most consistent with Comparison matrix?', '[{"id": "a", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "BNP elevation is impossible in right HF according to this note."}, {"id": "d", "text": "Use pattern recognition for side differentiation."}]'::jsonb, '["d"]'::jsonb, 'Correct because Left HF = lungs; right HF = body; BNP can be elevated in both; valve associations differ. Use pattern recognition for side differentiation.', 'Right-Left Heart Failure - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports General therapy?', 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports General therapy?', '[{"id": "a", "text": "General treatment includes diuretics, ACEI/ARB, beta-blockers, sodium restriction, daily weight monitoring, and fluid restriction in severe HF."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "d", "text": "This finding is more consistent with Digoxin-furosemide risk."}]'::jsonb, '["a"]'::jsonb, 'Correct because General treatment includes diuretics, ACEI/ARB, beta-blockers, sodium restriction, daily weight monitoring, and fluid restriction in severe HF. Prioritize evidence-aligned daily management bundle.', 'Right-Left Heart Failure - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During clinical handoff, which interpretation is most accurate for Weight reporting thresholds?', 'During clinical handoff, which interpretation is most accurate for Weight reporting thresholds?', '[{"id": "a", "text": "Escalate early before severe decompensation."}, {"id": "b", "text": "Any weight change under 10 lb/day is ignored in this note."}, {"id": "c", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "d", "text": "This finding is more consistent with Digoxin toxicity signs."}]'::jsonb, '["a"]'::jsonb, 'Correct because Report >2 lb in 24 h or >5 lb in a week. Escalate early before severe decompensation.', 'Right-Left Heart Failure - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse is prioritizing care. Which statement best reflects Left-specific therapy?', 'The nurse is prioritizing care. Which statement best reflects Left-specific therapy?', '[{"id": "a", "text": "This finding is more consistent with Digoxin hold thresholds."}, {"id": "b", "text": "Immediate fluid bolus is first-line for pulmonary edema in this note."}, {"id": "c", "text": "Left HF specifics include high Fowler positioning, O2/BiPAP for refractory pulmonary edema, digoxin for AF+HF rate control, spironolactone, LVAD/transplant for refractory HFrEF."}, {"id": "d", "text": "BiPAP is contraindicated in refractory pulmonary edema per this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Left HF specifics include high Fowler positioning, O2/BiPAP for refractory pulmonary edema, digoxin for AF+HF rate control, spironolactone, LVAD/transplant for refractory HFrEF. Match intervention to pulmonary decompensation severity.', 'Right-Left Heart Failure - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A complex symptom cluster is reviewed. Which conclusion best matches Digoxin-furosemide risk?', 'A complex symptom cluster is reviewed. Which conclusion best matches Digoxin-furosemide risk?', '[{"id": "a", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "b", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "c", "text": "This finding is more consistent with HF Definition."}, {"id": "d", "text": "Prevent medication-related deterioration."}]'::jsonb, '["d"]'::jsonb, 'Correct because Furosemide can lower potassium, increasing digoxin toxicity risk. Prevent medication-related deterioration.', 'Right-Left Heart Failure - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Digoxin toxicity signs?', 'Which clinical judgment is most consistent with Digoxin toxicity signs?', '[{"id": "a", "text": "Early digoxin toxicity signs listed are nausea/vomiting and visual disturbances (halos)."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "d", "text": "This finding is more consistent with HFrEF."}]'::jsonb, '["a"]'::jsonb, 'Correct because Early digoxin toxicity signs listed are nausea/vomiting and visual disturbances (halos). Hold and escalate promptly when early toxicity appears.', 'Right-Left Heart Failure - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Digoxin hold thresholds?', 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Digoxin hold thresholds?', '[{"id": "a", "text": "Apply age-specific hold parameters accurately."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "This finding is more consistent with HFpEF."}, {"id": "d", "text": "The same 60 bpm threshold applies to all ages in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Hold digoxin for HR <60 adult, <70 child, <90 infant. Apply age-specific hold parameters accurately.', 'Right-Left Heart Failure - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During clinical handoff, which interpretation is most accurate for HF Definition?', 'During clinical handoff, which interpretation is most accurate for HF Definition?', '[{"id": "a", "text": "Heart failure is the inability of the heart to pump sufficient blood to meet metabolic needs."}, {"id": "b", "text": "This finding is more consistent with EF Range."}, {"id": "c", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "d", "text": "Fluid trends are not useful for cardiovascular reassessment."}]'::jsonb, '["a"]'::jsonb, 'Correct because Heart failure is the inability of the heart to pump sufficient blood to meet metabolic needs. Recognize that congestion and low forward output can coexist.', 'Right-Left Heart Failure - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse is prioritizing care. Which statement best reflects HFrEF?', 'The nurse is prioritizing care. Which statement best reflects HFrEF?', '[{"id": "a", "text": "This finding is more consistent with Left HF Core."}, {"id": "b", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "c", "text": "Link reduced EF with weakened pump function."}, {"id": "d", "text": "HFrEF is primarily a stiff non-compliant ventricle with preserved EF."}]'::jsonb, '["c"]'::jsonb, 'Correct because HFrEF has EF <40% with a dilated, weak heart. Link reduced EF with weakened pump function.', 'Right-Left Heart Failure - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A complex symptom cluster is reviewed. Which conclusion best matches HFpEF?', 'A complex symptom cluster is reviewed. Which conclusion best matches HFpEF?', '[{"id": "a", "text": "HFpEF has EF >50% with a stiff, non-compliant heart."}, {"id": "b", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "c", "text": "HFpEF is a dilated weak ventricle by definition."}, {"id": "d", "text": "This finding is more consistent with Left HF Causes."}]'::jsonb, '["a"]'::jsonb, 'Correct because HFpEF has EF >50% with a stiff, non-compliant heart. Avoid ruling out HF just because EF is preserved.', 'Right-Left Heart Failure - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with EF Range?', 'Which clinical judgment is most consistent with EF Range?', '[{"id": "a", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "b", "text": "This finding is more consistent with Left HF Path."}, {"id": "c", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "d", "text": "Prioritize clinical symptoms over EF alone."}]'::jsonb, '["d"]'::jsonb, 'Correct because Normal EF is 55-70%; HF diagnosis can still be made if symptoms are present regardless of EF. Prioritize clinical symptoms over EF alone.', 'Right-Left Heart Failure - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Left HF Core?', 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Left HF Core?', '[{"id": "a", "text": "This finding is more consistent with DOE."}, {"id": "b", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "c", "text": "Left-sided HF primarily causes pulmonary congestion."}, {"id": "d", "text": "This finding excludes heart failure when EF is preserved."}]'::jsonb, '["c"]'::jsonb, 'Correct because Left-sided HF primarily causes pulmonary congestion. Map left side findings to lung congestion.', 'Right-Left Heart Failure - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During clinical handoff, which interpretation is most accurate for Left HF Causes?', 'During clinical handoff, which interpretation is most accurate for Left HF Causes?', '[{"id": "a", "text": "Connect structural and ischemic causes to LV failure."}, {"id": "b", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "c", "text": "This finding is more consistent with Orthopnea and PND."}, {"id": "d", "text": "No further assessment is needed when symptoms fluctuate."}]'::jsonb, '["a"]'::jsonb, 'Correct because Left HF causes include mitral/aortic valve disease, MI, chronic hypertension, cardiomyopathy. Connect structural and ischemic causes to LV failure.', 'Right-Left Heart Failure - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse is prioritizing care. Which statement best reflects Left HF Path?', 'The nurse is prioritizing care. Which statement best reflects Left HF Path?', '[{"id": "a", "text": "Left HF pathophysiology in the note excludes alveolar fluid leakage."}, {"id": "b", "text": "LV failure first causes isolated portal venous congestion in the note."}, {"id": "c", "text": "LV failure backs blood into pulmonary veins; pressure rises and fluid leaks into alveoli causing pulmonary edema."}, {"id": "d", "text": "This finding is more consistent with Pulmonary edema."}]'::jsonb, '["c"]'::jsonb, 'Correct because LV failure backs blood into pulmonary veins; pressure rises and fluid leaks into alveoli causing pulmonary edema. Identify sequence leading to respiratory compromise.', 'Right-Left Heart Failure - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A complex symptom cluster is reviewed. Which conclusion best matches DOE?', 'A complex symptom cluster is reviewed. Which conclusion best matches DOE?', '[{"id": "a", "text": "DOE appears only in right-sided HF section in this note."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "This finding is more consistent with S3."}, {"id": "d", "text": "Escalate evaluation when exertional dyspnea appears in risk patients."}]'::jsonb, '["d"]'::jsonb, 'Correct because Dyspnea on exertion is the first symptom listed for left HF. Escalate evaluation when exertional dyspnea appears in risk patients.', 'Right-Left Heart Failure - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Orthopnea and PND?', 'Which clinical judgment is most consistent with Orthopnea and PND?', '[{"id": "a", "text": "Orthopnea is identified as a right-sided-only symptom in this note."}, {"id": "b", "text": "This finding is more consistent with Right HF Core."}, {"id": "c", "text": "Orthopnea and PND are classic left-sided HF symptoms."}, {"id": "d", "text": "This finding excludes heart failure when EF is preserved."}]'::jsonb, '["c"]'::jsonb, 'Correct because Orthopnea and PND are classic left-sided HF symptoms. Use nocturnal and positional dyspnea to triage severity.', 'Right-Left Heart Failure - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Pulmonary edema?', 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Pulmonary edema?', '[{"id": "a", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "b", "text": "Pink frothy sputum is listed as a benign right-sided finding."}, {"id": "c", "text": "This finding is more consistent with Right HF Causes."}, {"id": "d", "text": "Treat as high-acuity respiratory compromise."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pink frothy sputum is a severe pulmonary edema sign in left HF. Treat as high-acuity respiratory compromise.', 'Right-Left Heart Failure - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During clinical handoff, which interpretation is most accurate for S3?', 'During clinical handoff, which interpretation is most accurate for S3?', '[{"id": "a", "text": "S3 is only a normal physiologic finding in this note."}, {"id": "b", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "c", "text": "S3 gallop is described as a hallmark of heart failure (especially in left HF section)."}, {"id": "d", "text": "S3 excludes heart failure in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because S3 gallop is described as a hallmark of heart failure (especially in left HF section). Interpret S3 with full volume-overload context.', 'Right-Left Heart Failure - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse is prioritizing care. Which statement best reflects Right HF Core?', 'The nurse is prioritizing care. Which statement best reflects Right HF Core?', '[{"id": "a", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "b", "text": "Right-sided HF is described as isolated alveolar edema only."}, {"id": "c", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "d", "text": "Distinguish body-fluid retention pattern from pulmonary pattern."}]'::jsonb, '["d"]'::jsonb, 'Correct because Right-sided HF primarily causes systemic (peripheral) congestion. Distinguish body-fluid retention pattern from pulmonary pattern.', 'Right-Left Heart Failure - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A complex symptom cluster is reviewed. Which conclusion best matches Right HF Causes?', 'A complex symptom cluster is reviewed. Which conclusion best matches Right HF Causes?', '[{"id": "a", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "b", "text": "Right-sided HF in this note is unrelated to chronic lung disease."}, {"id": "c", "text": "Most common right HF cause is left-sided HF; others include tricuspid disease, pulmonary HTN, RV MI, chronic lung disease."}, {"id": "d", "text": "This finding is more consistent with Peripheral edema."}]'::jsonb, '["c"]'::jsonb, 'Correct because Most common right HF cause is left-sided HF; others include tricuspid disease, pulmonary HTN, RV MI, chronic lung disease. Search upstream causes when right-sided findings appear.', 'Right-Left Heart Failure - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Right HF Path?', 'Which clinical judgment is most consistent with Right HF Path?', '[{"id": "a", "text": "Connect venous pressure rise to peripheral signs."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "d", "text": "No further assessment is needed when symptoms fluctuate."}]'::jsonb, '["a"]'::jsonb, 'Correct because RV failure causes venous backup and systemic fluid accumulation. Connect venous pressure rise to peripheral signs.', 'Right-Left Heart Failure - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports JVD?', 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports JVD?', '[{"id": "a", "text": "JVD indicates low venous pressure in this note."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "This finding is more consistent with Ascites/hepatomegaly."}, {"id": "d", "text": "JVD reflects elevated venous pressure and is a major right HF sign."}]'::jsonb, '["d"]'::jsonb, 'Correct because JVD reflects elevated venous pressure and is a major right HF sign. Use JVD as high-yield bedside congestion marker.', 'Right-Left Heart Failure - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During clinical handoff, which interpretation is most accurate for Peripheral edema?', 'During clinical handoff, which interpretation is most accurate for Peripheral edema?', '[{"id": "a", "text": "Trend bilateral edema and rapid fluid changes."}, {"id": "b", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "c", "text": "This finding is more consistent with Cor pulmonale."}, {"id": "d", "text": "No further assessment is needed when symptoms fluctuate."}]'::jsonb, '["a"]'::jsonb, 'Correct because Right HF commonly causes bilateral peripheral pitting edema. Trend bilateral edema and rapid fluid changes.', 'Right-Left Heart Failure - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse is prioritizing care. Which statement best reflects Weight rule physiology?', 'The nurse is prioritizing care. Which statement best reflects Weight rule physiology?', '[{"id": "a", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "b", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "c", "text": "Weight changes are considered unreliable and not used in HF monitoring in this note."}, {"id": "d", "text": "Rapid gain indicates fluid retention; 1 kg equals about 1 liter."}]'::jsonb, '["d"]'::jsonb, 'Correct because Rapid gain indicates fluid retention; 1 kg equals about 1 liter. Use objective weight data for early decompensation detection.', 'Right-Left Heart Failure - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A complex symptom cluster is reviewed. Which conclusion best matches Ascites/hepatomegaly?', 'A complex symptom cluster is reviewed. Which conclusion best matches Ascites/hepatomegaly?', '[{"id": "a", "text": "Hepatomegaly in this note is unrelated to venous congestion."}, {"id": "b", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "c", "text": "Recognize abdominal signs as venous-congestion progression."}, {"id": "d", "text": "This finding excludes heart failure when EF is preserved."}]'::jsonb, '["c"]'::jsonb, 'Correct because Severe right HF can cause ascites and hepatomegaly with RUQ discomfort; GI congestion can cause nausea/anorexia. Recognize abdominal signs as venous-congestion progression.', 'Right-Left Heart Failure - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Cor pulmonale?', 'Which clinical judgment is most consistent with Cor pulmonale?', '[{"id": "a", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "b", "text": "Chronic lung disease raises pulmonary vascular resistance and can lead to RV failure/right HF."}, {"id": "c", "text": "This finding is more consistent with Weight reporting thresholds."}, {"id": "d", "text": "Chronic lung disease reduces RV workload in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Chronic lung disease raises pulmonary vascular resistance and can lead to RV failure/right HF. Identify cardiopulmonary linkage in chronic lung patients.', 'Right-Left Heart Failure - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Comparison matrix?', 'A patient with cardiovascular decompensation is being reassessed. Which finding most strongly supports Comparison matrix?', '[{"id": "a", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "b", "text": "BNP elevation is impossible in right HF according to this note."}, {"id": "c", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "d", "text": "Use pattern recognition for side differentiation."}]'::jsonb, '["d"]'::jsonb, 'Correct because Left HF = lungs; right HF = body; BNP can be elevated in both; valve associations differ. Use pattern recognition for side differentiation.', 'Right-Left Heart Failure - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During clinical handoff, which interpretation is most accurate for General therapy?', 'During clinical handoff, which interpretation is most accurate for General therapy?', '[{"id": "a", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "b", "text": "Fluid trends are not useful for cardiovascular reassessment."}, {"id": "c", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "d", "text": "General treatment includes diuretics, ACEI/ARB, beta-blockers, sodium restriction, daily weight monitoring, and fluid restriction in severe HF."}]'::jsonb, '["d"]'::jsonb, 'Correct because General treatment includes diuretics, ACEI/ARB, beta-blockers, sodium restriction, daily weight monitoring, and fluid restriction in severe HF. Prioritize evidence-aligned daily management bundle.', 'Right-Left Heart Failure - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse is prioritizing care. Which statement best reflects Weight reporting thresholds?', 'The nurse is prioritizing care. Which statement best reflects Weight reporting thresholds?', '[{"id": "a", "text": "This finding excludes heart failure when EF is preserved."}, {"id": "b", "text": "This finding is more consistent with Digoxin toxicity signs."}, {"id": "c", "text": "Escalate early before severe decompensation."}, {"id": "d", "text": "Any weight change under 10 lb/day is ignored in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Report >2 lb in 24 h or >5 lb in a week. Escalate early before severe decompensation.', 'Right-Left Heart Failure - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A complex symptom cluster is reviewed. Which conclusion best matches Left-specific therapy?', 'A complex symptom cluster is reviewed. Which conclusion best matches Left-specific therapy?', '[{"id": "a", "text": "BiPAP is contraindicated in refractory pulmonary edema per this note."}, {"id": "b", "text": "No further assessment is needed when symptoms fluctuate."}, {"id": "c", "text": "Left HF specifics include high Fowler positioning, O2/BiPAP for refractory pulmonary edema, digoxin for AF+HF rate control, spironolactone, LVAD/transplant for refractory HFrEF."}, {"id": "d", "text": "Immediate fluid bolus is first-line for pulmonary edema in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Left HF specifics include high Fowler positioning, O2/BiPAP for refractory pulmonary edema, digoxin for AF+HF rate control, spironolactone, LVAD/transplant for refractory HFrEF. Match intervention to pulmonary decompensation severity.', 'Right-Left Heart Failure - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Digoxin-furosemide risk?', 'Which clinical judgment is most consistent with Digoxin-furosemide risk?', '[{"id": "a", "text": "Prevent medication-related deterioration."}, {"id": "b", "text": "This finding is more consistent with HF Definition."}, {"id": "c", "text": "No electrolyte monitoring is needed when combining these drugs per this note."}, {"id": "d", "text": "No further assessment is needed when symptoms fluctuate."}]'::jsonb, '["a"]'::jsonb, 'Correct because Furosemide can lower potassium, increasing digoxin toxicity risk. Prevent medication-related deterioration.', 'Right-Left Heart Failure - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for HF Definition. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for HF Definition. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Heart failure can cause backward fluid congestion."}, {"id": "b", "text": "Heart failure means the heart cannot pump enough blood to meet metabolic demand."}, {"id": "c", "text": "Heart failure requires an ejection fraction below 20% in all patients."}, {"id": "d", "text": "Heart failure always presents without fluid overload."}, {"id": "e", "text": "Heart failure can reduce forward perfusion."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Heart failure is the inability of the heart to pump sufficient blood to meet metabolic needs.', 'Right-Left Heart Failure - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected HFrEF, which statements are correct? (Select all that apply)', 'For a patient with suspected HFrEF, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Reduced contractility contributes to poor forward output in HFrEF."}, {"id": "b", "text": "HFrEF is commonly described as a dilated, weak heart."}, {"id": "c", "text": "HFrEF is associated with EF below 40%."}, {"id": "d", "text": "HFrEF is defined by EF above 50%."}, {"id": "e", "text": "HFrEF is primarily a stiff non-compliant ventricle with preserved EF."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: HFrEF has EF <40% with a dilated, weak heart.', 'Right-Left Heart Failure - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for HFpEF. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for HFpEF. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "HFpEF excludes all congestion symptoms."}, {"id": "b", "text": "HFpEF is a dilated weak ventricle by definition."}, {"id": "c", "text": "HFpEF is described as a stiff, non-compliant ventricle."}, {"id": "d", "text": "HFpEF is associated with EF above 50%."}, {"id": "e", "text": "Symptoms may still indicate heart failure even with preserved EF."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: HFpEF has EF >50% with a stiff, non-compliant heart.', 'Right-Left Heart Failure - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about EF Range, which points are accurate? (Select all that apply)', 'During patient teaching about EF Range, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Symptoms remain central to HF diagnosis."}, {"id": "b", "text": "Normal EF is approximately 55-70%."}, {"id": "c", "text": "EF alone is always enough to diagnose or exclude HF."}, {"id": "d", "text": "Any EF above 50% rules out heart failure."}, {"id": "e", "text": "A patient can have HF symptoms even when EF is preserved."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Normal EF is 55-70%; HF diagnosis can still be made if symptoms are present regardless of EF.', 'Right-Left Heart Failure - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Left HF Core? (Select all that apply)', 'Which assessment findings support Left HF Core? (Select all that apply)', '[{"id": "a", "text": "Left-sided HF causes pulmonary congestion."}, {"id": "b", "text": "Dyspnea and crackles are hallmark left-sided findings."}, {"id": "c", "text": "Left-sided HF typically has no respiratory symptoms."}, {"id": "d", "text": "Left-sided HF primarily causes isolated ankle edema without lung findings."}, {"id": "e", "text": "Orthopnea strongly supports left-sided congestion."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Left-sided HF primarily causes pulmonary congestion.', 'Right-Left Heart Failure - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Left HF Causes. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Left HF Causes. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Anterior MI and chronic hypertension are common contributors."}, {"id": "b", "text": "Mitral valve disease can cause left-sided HF."}, {"id": "c", "text": "Left HF is unrelated to cardiomyopathy."}, {"id": "d", "text": "Tricuspid disease is listed as the most common isolated cause of left HF in this note."}, {"id": "e", "text": "Aortic valve disease can precipitate left-sided HF."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Left HF causes include mitral/aortic valve disease, MI, chronic hypertension, cardiomyopathy.', 'Right-Left Heart Failure - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Left HF Path, which statements are correct? (Select all that apply)', 'For a patient with suspected Left HF Path, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "LV failure causes pulmonary venous backup."}, {"id": "b", "text": "Left HF pathophysiology in the note excludes alveolar fluid leakage."}, {"id": "c", "text": "Increased pulmonary venous pressure can push fluid into alveoli."}, {"id": "d", "text": "Pulmonary edema can result from this process."}, {"id": "e", "text": "LV failure first causes isolated portal venous congestion in the note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: LV failure backs blood into pulmonary veins; pressure rises and fluid leaks into alveoli causing pulmonary edema.', 'Right-Left Heart Failure - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for DOE. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for DOE. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Dyspnea on exertion is an early left HF symptom."}, {"id": "b", "text": "Progressive exertional intolerance supports worsening congestion."}, {"id": "c", "text": "DOE should prompt reassessment of fluid status and respiratory findings."}, {"id": "d", "text": "DOE is unrelated to left HF in this note."}, {"id": "e", "text": "DOE appears only in right-sided HF section in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Dyspnea on exertion is the first symptom listed for left HF.', 'Right-Left Heart Failure - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Orthopnea and PND, which points are accurate? (Select all that apply)', 'During patient teaching about Orthopnea and PND, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Orthopnea is identified as a right-sided-only symptom in this note."}, {"id": "b", "text": "Both findings support pulmonary congestion from left HF."}, {"id": "c", "text": "PND involves waking at night gasping for air."}, {"id": "d", "text": "Orthopnea means inability to lie flat without dyspnea."}, {"id": "e", "text": "PND indicates isolated GI congestion in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Orthopnea and PND are classic left-sided HF symptoms.', 'Right-Left Heart Failure - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Pulmonary edema? (Select all that apply)', 'Which assessment findings support Pulmonary edema? (Select all that apply)', '[{"id": "a", "text": "Pink frothy sputum indicates severe pulmonary edema."}, {"id": "b", "text": "Respiratory compromise may escalate rapidly when this appears."}, {"id": "c", "text": "Pulmonary edema is strongly linked to left-sided failure in the note."}, {"id": "d", "text": "Pulmonary edema is excluded from left HF in this note."}, {"id": "e", "text": "Pink frothy sputum is listed as a benign right-sided finding."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Pink frothy sputum is a severe pulmonary edema sign in left HF.', 'Right-Left Heart Failure - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for S3. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for S3. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "S3 excludes heart failure in this note."}, {"id": "b", "text": "S3 may be present with left-sided congestion."}, {"id": "c", "text": "S3 is only a normal physiologic finding in this note."}, {"id": "d", "text": "S3 should be integrated with dyspnea, crackles, and edema findings."}, {"id": "e", "text": "S3 gallop is a hallmark heart failure clue in this note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: S3 gallop is described as a hallmark of heart failure (especially in left HF section).', 'Right-Left Heart Failure - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Right HF Core, which statements are correct? (Select all that apply)', 'For a patient with suspected Right HF Core, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Right-sided HF is described as isolated alveolar edema only."}, {"id": "b", "text": "Right-sided HF causes systemic venous congestion."}, {"id": "c", "text": "Peripheral edema and JVD are key right-sided clues."}, {"id": "d", "text": "Right-sided HF has no venous pressure effects in this note."}, {"id": "e", "text": "Weight gain from fluid retention supports right-sided congestion."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Right-sided HF primarily causes systemic (peripheral) congestion.', 'Right-Left Heart Failure - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Right HF Causes. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Right HF Causes. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Aortic stenosis is listed as the dominant right-sided cause in this note."}, {"id": "b", "text": "Left-sided HF is the most common cause of right-sided HF in this note."}, {"id": "c", "text": "RV MI and tricuspid disease are listed right-sided causes."}, {"id": "d", "text": "Pulmonary hypertension can drive right-sided failure."}, {"id": "e", "text": "Right-sided HF in this note is unrelated to chronic lung disease."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Most common right HF cause is left-sided HF; others include tricuspid disease, pulmonary HTN, RV MI, chronic lung disease.', 'Right-Left Heart Failure - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Right HF Path, which points are accurate? (Select all that apply)', 'During patient teaching about Right HF Path, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "RV failure causes blood to back up in venous circulation."}, {"id": "b", "text": "Peripheral congestion results from this mechanism."}, {"id": "c", "text": "Systemic venous pressure rise promotes body fluid accumulation."}, {"id": "d", "text": "RV failure in this note directly causes only alveolar edema."}, {"id": "e", "text": "RV failure in this note lowers venous pressure and prevents edema."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: RV failure causes venous backup and systemic fluid accumulation.', 'Right-Left Heart Failure - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support JVD? (Select all that apply)', 'Which assessment findings support JVD? (Select all that apply)', '[{"id": "a", "text": "JVD with edema supports peripheral congestion."}, {"id": "b", "text": "JVD is listed as a hallmark of isolated left alveolar pathology in this note."}, {"id": "c", "text": "JVD is emphasized in right-sided HF symptom profile."}, {"id": "d", "text": "JVD suggests elevated systemic venous pressure."}, {"id": "e", "text": "JVD indicates low venous pressure in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: JVD reflects elevated venous pressure and is a major right HF sign.', 'Right-Left Heart Failure - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Peripheral edema. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Peripheral edema. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Dependent leg/ankle swelling is expected in systemic fluid overload."}, {"id": "b", "text": "Bilateral pitting edema supports right-sided congestion."}, {"id": "c", "text": "Peripheral edema is absent in right HF according to this note."}, {"id": "d", "text": "Peripheral edema should be interpreted with weight trends and JVD."}, {"id": "e", "text": "Unilateral trauma edema is listed as classic HF edema in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Right HF commonly causes bilateral peripheral pitting edema.', 'Right-Left Heart Failure - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Weight rule physiology, which statements are correct? (Select all that apply)', 'For a patient with suspected Weight rule physiology, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Rapid weight gain indicates fluid retention."}, {"id": "b", "text": "The note equates 1 kg to roughly 1 liter of retained fluid."}, {"id": "c", "text": "The note states 1 kg equals 100 mL of fluid."}, {"id": "d", "text": "Weight changes are considered unreliable and not used in HF monitoring in this note."}, {"id": "e", "text": "Daily weights are a core monitoring strategy."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Rapid gain indicates fluid retention; 1 kg equals about 1 liter.', 'Right-Left Heart Failure - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Ascites/hepatomegaly. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Ascites/hepatomegaly. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Ascites is listed as a defining left-sided pulmonary finding."}, {"id": "b", "text": "GI congestion may cause nausea and anorexia."}, {"id": "c", "text": "Hepatomegaly in this note is unrelated to venous congestion."}, {"id": "d", "text": "Ascites can occur in severe right-sided HF."}, {"id": "e", "text": "Hepatomegaly with RUQ discomfort is linked to hepatic congestion."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Severe right HF can cause ascites and hepatomegaly with RUQ discomfort; GI congestion can cause nausea/anorexia.', 'Right-Left Heart Failure - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Cor pulmonale, which points are accurate? (Select all that apply)', 'During patient teaching about Cor pulmonale, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Chronic lung disease reduces RV workload in this note."}, {"id": "b", "text": "Cor pulmonale links chronic lung disease to right-sided HF."}, {"id": "c", "text": "Increased pulmonary vascular resistance increases RV workload."}, {"id": "d", "text": "Cor pulmonale in this note is a left-ventricular primary valvular disorder."}, {"id": "e", "text": "JVD and peripheral edema can appear in COPD-related right HF."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Chronic lung disease raises pulmonary vascular resistance and can lead to RV failure/right HF.', 'Right-Left Heart Failure - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Comparison matrix? (Select all that apply)', 'Which assessment findings support Comparison matrix? (Select all that apply)', '[{"id": "a", "text": "BNP elevation is impossible in right HF according to this note."}, {"id": "b", "text": "Right HF primarily accumulates fluid in systemic tissues."}, {"id": "c", "text": "Left HF primarily accumulates fluid in lungs."}, {"id": "d", "text": "BNP can be elevated in both left and right HF."}, {"id": "e", "text": "Both sides are associated with the same valve pattern in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Left HF = lungs; right HF = body; BNP can be elevated in both; valve associations differ.', 'Right-Left Heart Failure - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for General therapy. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for General therapy. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Daily weights are discouraged in this note."}, {"id": "b", "text": "Beta-blockers reduce workload in chronic HF care."}, {"id": "c", "text": "ACE inhibitors or ARBs help reduce afterload and improve survival."}, {"id": "d", "text": "Sodium loading is recommended in this note."}, {"id": "e", "text": "Diuretics are used to reduce fluid overload."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: General treatment includes diuretics, ACEI/ARB, beta-blockers, sodium restriction, daily weight monitoring, and fluid restriction in severe HF.', 'Right-Left Heart Failure - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Weight reporting thresholds, which statements are correct? (Select all that apply)', 'For a patient with suspected Weight reporting thresholds, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Any weight change under 10 lb/day is ignored in this note."}, {"id": "b", "text": "Patients should report weight gain over 5 lb in one week."}, {"id": "c", "text": "Patients should report weight gain over 2 lb in 24 hours."}, {"id": "d", "text": "Using same time and same scale is emphasized."}, {"id": "e", "text": "Daily weighing time variability is preferred in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Report >2 lb in 24 h or >5 lb in a week.', 'Right-Left Heart Failure - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Left-specific therapy. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Left-specific therapy. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "BiPAP is contraindicated in refractory pulmonary edema per this note."}, {"id": "b", "text": "LVAD or transplant is considered in refractory HFrEF."}, {"id": "c", "text": "High Fowler positioning helps reduce preload in left HF."}, {"id": "d", "text": "Immediate fluid bolus is first-line for pulmonary edema in this note."}, {"id": "e", "text": "BiPAP is used for refractory pulmonary edema."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Left HF specifics include high Fowler positioning, O2/BiPAP for refractory pulmonary edema, digoxin for AF+HF rate control, spironolactone, LVAD/transplant for refractory HFrEF.', 'Right-Left Heart Failure - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Digoxin-furosemide risk, which points are accurate? (Select all that apply)', 'During patient teaching about Digoxin-furosemide risk, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Potassium monitoring is important when furosemide and digoxin are combined."}, {"id": "b", "text": "Loop diuretic-related hypokalemia increases digoxin toxicity risk."}, {"id": "c", "text": "Medication safety requires rhythm and symptom surveillance."}, {"id": "d", "text": "No electrolyte monitoring is needed when combining these drugs per this note."}, {"id": "e", "text": "Furosemide reliably raises potassium and protects from digoxin toxicity."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Furosemide can lower potassium, increasing digoxin toxicity risk.', 'Right-Left Heart Failure - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Digoxin toxicity signs? (Select all that apply)', 'Which assessment findings support Digoxin toxicity signs? (Select all that apply)', '[{"id": "a", "text": "Visual halos are listed as benign and expected in this note."}, {"id": "b", "text": "Nausea and vomiting are early digoxin toxicity signs in this note."}, {"id": "c", "text": "Visual halos are a toxicity warning sign in this note."}, {"id": "d", "text": "These findings warrant prompt medication review and provider notification."}, {"id": "e", "text": "Digoxin toxicity is described as asymptomatic in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Early digoxin toxicity signs listed are nausea/vomiting and visual disturbances (halos).', 'Right-Left Heart Failure - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Digoxin hold thresholds. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Digoxin hold thresholds. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Hold digoxin when child HR is below 70."}, {"id": "b", "text": "Hold digoxin when infant HR is below 90."}, {"id": "c", "text": "The same 60 bpm threshold applies to all ages in this note."}, {"id": "d", "text": "Hold digoxin when adult HR is below 60."}, {"id": "e", "text": "Digoxin is never held for bradycardia in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Hold digoxin for HR <60 adult, <70 child, <90 infant.', 'Right-Left Heart Failure - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected HF Definition, which statements are correct? (Select all that apply)', 'For a patient with suspected HF Definition, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Heart failure can reduce forward perfusion."}, {"id": "b", "text": "Heart failure always presents without fluid overload."}, {"id": "c", "text": "Heart failure requires an ejection fraction below 20% in all patients."}, {"id": "d", "text": "Heart failure can cause backward fluid congestion."}, {"id": "e", "text": "Heart failure means the heart cannot pump enough blood to meet metabolic demand."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Heart failure is the inability of the heart to pump sufficient blood to meet metabolic needs.', 'Right-Left Heart Failure - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for HFrEF. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for HFrEF. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "HFrEF is primarily a stiff non-compliant ventricle with preserved EF."}, {"id": "b", "text": "Reduced contractility contributes to poor forward output in HFrEF."}, {"id": "c", "text": "HFrEF is associated with EF below 40%."}, {"id": "d", "text": "HFrEF is commonly described as a dilated, weak heart."}, {"id": "e", "text": "HFrEF is defined by EF above 50%."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: HFrEF has EF <40% with a dilated, weak heart.', 'Right-Left Heart Failure - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about HFpEF, which points are accurate? (Select all that apply)', 'During patient teaching about HFpEF, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "HFpEF excludes all congestion symptoms."}, {"id": "b", "text": "HFpEF is a dilated weak ventricle by definition."}, {"id": "c", "text": "HFpEF is associated with EF above 50%."}, {"id": "d", "text": "HFpEF is described as a stiff, non-compliant ventricle."}, {"id": "e", "text": "Symptoms may still indicate heart failure even with preserved EF."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: HFpEF has EF >50% with a stiff, non-compliant heart.', 'Right-Left Heart Failure - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support EF Range? (Select all that apply)', 'Which assessment findings support EF Range? (Select all that apply)', '[{"id": "a", "text": "EF alone is always enough to diagnose or exclude HF."}, {"id": "b", "text": "Normal EF is approximately 55-70%."}, {"id": "c", "text": "Any EF above 50% rules out heart failure."}, {"id": "d", "text": "A patient can have HF symptoms even when EF is preserved."}, {"id": "e", "text": "Symptoms remain central to HF diagnosis."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Normal EF is 55-70%; HF diagnosis can still be made if symptoms are present regardless of EF.', 'Right-Left Heart Failure - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Left HF Core. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Left HF Core. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Left-sided HF primarily causes isolated ankle edema without lung findings."}, {"id": "b", "text": "Orthopnea strongly supports left-sided congestion."}, {"id": "c", "text": "Left-sided HF causes pulmonary congestion."}, {"id": "d", "text": "Dyspnea and crackles are hallmark left-sided findings."}, {"id": "e", "text": "Left-sided HF typically has no respiratory symptoms."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Left-sided HF primarily causes pulmonary congestion.', 'Right-Left Heart Failure - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Left HF Causes, which statements are correct? (Select all that apply)', 'For a patient with suspected Left HF Causes, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Mitral valve disease can cause left-sided HF."}, {"id": "b", "text": "Left HF is unrelated to cardiomyopathy."}, {"id": "c", "text": "Tricuspid disease is listed as the most common isolated cause of left HF in this note."}, {"id": "d", "text": "Aortic valve disease can precipitate left-sided HF."}, {"id": "e", "text": "Anterior MI and chronic hypertension are common contributors."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Left HF causes include mitral/aortic valve disease, MI, chronic hypertension, cardiomyopathy.', 'Right-Left Heart Failure - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Left HF Path. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Left HF Path. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Left HF pathophysiology in the note excludes alveolar fluid leakage."}, {"id": "b", "text": "LV failure first causes isolated portal venous congestion in the note."}, {"id": "c", "text": "Increased pulmonary venous pressure can push fluid into alveoli."}, {"id": "d", "text": "LV failure causes pulmonary venous backup."}, {"id": "e", "text": "Pulmonary edema can result from this process."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: LV failure backs blood into pulmonary veins; pressure rises and fluid leaks into alveoli causing pulmonary edema.', 'Right-Left Heart Failure - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about DOE, which points are accurate? (Select all that apply)', 'During patient teaching about DOE, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "DOE appears only in right-sided HF section in this note."}, {"id": "b", "text": "Dyspnea on exertion is an early left HF symptom."}, {"id": "c", "text": "Progressive exertional intolerance supports worsening congestion."}, {"id": "d", "text": "DOE should prompt reassessment of fluid status and respiratory findings."}, {"id": "e", "text": "DOE is unrelated to left HF in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Dyspnea on exertion is the first symptom listed for left HF.', 'Right-Left Heart Failure - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Orthopnea and PND? (Select all that apply)', 'Which assessment findings support Orthopnea and PND? (Select all that apply)', '[{"id": "a", "text": "PND indicates isolated GI congestion in this note."}, {"id": "b", "text": "PND involves waking at night gasping for air."}, {"id": "c", "text": "Orthopnea means inability to lie flat without dyspnea."}, {"id": "d", "text": "Both findings support pulmonary congestion from left HF."}, {"id": "e", "text": "Orthopnea is identified as a right-sided-only symptom in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Orthopnea and PND are classic left-sided HF symptoms.', 'Right-Left Heart Failure - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Pulmonary edema. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Pulmonary edema. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Pink frothy sputum indicates severe pulmonary edema."}, {"id": "b", "text": "Respiratory compromise may escalate rapidly when this appears."}, {"id": "c", "text": "Pulmonary edema is excluded from left HF in this note."}, {"id": "d", "text": "Pink frothy sputum is listed as a benign right-sided finding."}, {"id": "e", "text": "Pulmonary edema is strongly linked to left-sided failure in the note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pink frothy sputum is a severe pulmonary edema sign in left HF.', 'Right-Left Heart Failure - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected S3, which statements are correct? (Select all that apply)', 'For a patient with suspected S3, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "S3 should be integrated with dyspnea, crackles, and edema findings."}, {"id": "b", "text": "S3 may be present with left-sided congestion."}, {"id": "c", "text": "S3 gallop is a hallmark heart failure clue in this note."}, {"id": "d", "text": "S3 excludes heart failure in this note."}, {"id": "e", "text": "S3 is only a normal physiologic finding in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: S3 gallop is described as a hallmark of heart failure (especially in left HF section).', 'Right-Left Heart Failure - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Right HF Core. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Right HF Core. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Right-sided HF is described as isolated alveolar edema only."}, {"id": "b", "text": "Weight gain from fluid retention supports right-sided congestion."}, {"id": "c", "text": "Right-sided HF has no venous pressure effects in this note."}, {"id": "d", "text": "Right-sided HF causes systemic venous congestion."}, {"id": "e", "text": "Peripheral edema and JVD are key right-sided clues."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Right-sided HF primarily causes systemic (peripheral) congestion.', 'Right-Left Heart Failure - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Right HF Causes, which points are accurate? (Select all that apply)', 'During patient teaching about Right HF Causes, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Aortic stenosis is listed as the dominant right-sided cause in this note."}, {"id": "b", "text": "Right-sided HF in this note is unrelated to chronic lung disease."}, {"id": "c", "text": "Pulmonary hypertension can drive right-sided failure."}, {"id": "d", "text": "RV MI and tricuspid disease are listed right-sided causes."}, {"id": "e", "text": "Left-sided HF is the most common cause of right-sided HF in this note."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Most common right HF cause is left-sided HF; others include tricuspid disease, pulmonary HTN, RV MI, chronic lung disease.', 'Right-Left Heart Failure - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Right HF Path? (Select all that apply)', 'Which assessment findings support Right HF Path? (Select all that apply)', '[{"id": "a", "text": "Peripheral congestion results from this mechanism."}, {"id": "b", "text": "RV failure in this note directly causes only alveolar edema."}, {"id": "c", "text": "Systemic venous pressure rise promotes body fluid accumulation."}, {"id": "d", "text": "RV failure in this note lowers venous pressure and prevents edema."}, {"id": "e", "text": "RV failure causes blood to back up in venous circulation."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: RV failure causes venous backup and systemic fluid accumulation.', 'Right-Left Heart Failure - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for JVD. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for JVD. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "JVD indicates low venous pressure in this note."}, {"id": "b", "text": "JVD with edema supports peripheral congestion."}, {"id": "c", "text": "JVD suggests elevated systemic venous pressure."}, {"id": "d", "text": "JVD is emphasized in right-sided HF symptom profile."}, {"id": "e", "text": "JVD is listed as a hallmark of isolated left alveolar pathology in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: JVD reflects elevated venous pressure and is a major right HF sign.', 'Right-Left Heart Failure - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Peripheral edema, which statements are correct? (Select all that apply)', 'For a patient with suspected Peripheral edema, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Bilateral pitting edema supports right-sided congestion."}, {"id": "b", "text": "Peripheral edema is absent in right HF according to this note."}, {"id": "c", "text": "Peripheral edema should be interpreted with weight trends and JVD."}, {"id": "d", "text": "Dependent leg/ankle swelling is expected in systemic fluid overload."}, {"id": "e", "text": "Unilateral trauma edema is listed as classic HF edema in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Right HF commonly causes bilateral peripheral pitting edema.', 'Right-Left Heart Failure - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Weight rule physiology. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Weight rule physiology. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Daily weights are a core monitoring strategy."}, {"id": "b", "text": "Weight changes are considered unreliable and not used in HF monitoring in this note."}, {"id": "c", "text": "The note equates 1 kg to roughly 1 liter of retained fluid."}, {"id": "d", "text": "The note states 1 kg equals 100 mL of fluid."}, {"id": "e", "text": "Rapid weight gain indicates fluid retention."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Rapid gain indicates fluid retention; 1 kg equals about 1 liter.', 'Right-Left Heart Failure - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Ascites/hepatomegaly, which points are accurate? (Select all that apply)', 'During patient teaching about Ascites/hepatomegaly, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "GI congestion may cause nausea and anorexia."}, {"id": "b", "text": "Ascites is listed as a defining left-sided pulmonary finding."}, {"id": "c", "text": "Ascites can occur in severe right-sided HF."}, {"id": "d", "text": "Hepatomegaly with RUQ discomfort is linked to hepatic congestion."}, {"id": "e", "text": "Hepatomegaly in this note is unrelated to venous congestion."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Severe right HF can cause ascites and hepatomegaly with RUQ discomfort; GI congestion can cause nausea/anorexia.', 'Right-Left Heart Failure - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Cor pulmonale? (Select all that apply)', 'Which assessment findings support Cor pulmonale? (Select all that apply)', '[{"id": "a", "text": "Cor pulmonale links chronic lung disease to right-sided HF."}, {"id": "b", "text": "Chronic lung disease reduces RV workload in this note."}, {"id": "c", "text": "JVD and peripheral edema can appear in COPD-related right HF."}, {"id": "d", "text": "Increased pulmonary vascular resistance increases RV workload."}, {"id": "e", "text": "Cor pulmonale in this note is a left-ventricular primary valvular disorder."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Chronic lung disease raises pulmonary vascular resistance and can lead to RV failure/right HF.', 'Right-Left Heart Failure - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Comparison matrix. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Comparison matrix. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "BNP can be elevated in both left and right HF."}, {"id": "b", "text": "Both sides are associated with the same valve pattern in this note."}, {"id": "c", "text": "BNP elevation is impossible in right HF according to this note."}, {"id": "d", "text": "Right HF primarily accumulates fluid in systemic tissues."}, {"id": "e", "text": "Left HF primarily accumulates fluid in lungs."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Left HF = lungs; right HF = body; BNP can be elevated in both; valve associations differ.', 'Right-Left Heart Failure - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected General therapy, which statements are correct? (Select all that apply)', 'For a patient with suspected General therapy, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Beta-blockers reduce workload in chronic HF care."}, {"id": "b", "text": "Sodium loading is recommended in this note."}, {"id": "c", "text": "ACE inhibitors or ARBs help reduce afterload and improve survival."}, {"id": "d", "text": "Daily weights are discouraged in this note."}, {"id": "e", "text": "Diuretics are used to reduce fluid overload."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: General treatment includes diuretics, ACEI/ARB, beta-blockers, sodium restriction, daily weight monitoring, and fluid restriction in severe HF.', 'Right-Left Heart Failure - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Weight reporting thresholds. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Weight reporting thresholds. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Daily weighing time variability is preferred in this note."}, {"id": "b", "text": "Any weight change under 10 lb/day is ignored in this note."}, {"id": "c", "text": "Using same time and same scale is emphasized."}, {"id": "d", "text": "Patients should report weight gain over 5 lb in one week."}, {"id": "e", "text": "Patients should report weight gain over 2 lb in 24 hours."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Report >2 lb in 24 h or >5 lb in a week.', 'Right-Left Heart Failure - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Left-specific therapy, which points are accurate? (Select all that apply)', 'During patient teaching about Left-specific therapy, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "High Fowler positioning helps reduce preload in left HF."}, {"id": "b", "text": "LVAD or transplant is considered in refractory HFrEF."}, {"id": "c", "text": "BiPAP is contraindicated in refractory pulmonary edema per this note."}, {"id": "d", "text": "BiPAP is used for refractory pulmonary edema."}, {"id": "e", "text": "Immediate fluid bolus is first-line for pulmonary edema in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Left HF specifics include high Fowler positioning, O2/BiPAP for refractory pulmonary edema, digoxin for AF+HF rate control, spironolactone, LVAD/transplant for refractory HFrEF.', 'Right-Left Heart Failure - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Digoxin-furosemide risk? (Select all that apply)', 'Which assessment findings support Digoxin-furosemide risk? (Select all that apply)', '[{"id": "a", "text": "Furosemide reliably raises potassium and protects from digoxin toxicity."}, {"id": "b", "text": "No electrolyte monitoring is needed when combining these drugs per this note."}, {"id": "c", "text": "Potassium monitoring is important when furosemide and digoxin are combined."}, {"id": "d", "text": "Medication safety requires rhythm and symptom surveillance."}, {"id": "e", "text": "Loop diuretic-related hypokalemia increases digoxin toxicity risk."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Furosemide can lower potassium, increasing digoxin toxicity risk.', 'Right-Left Heart Failure - NCLEX', true, 100, 1, true);
